const items = $input.all();
return items.map(item => {
  const topic   = item.json.title ?? item.json.chunk_text.slice(0, 100);
  const excerpt = item.json.chunk_text.slice(0, 500);
  const lyriaPrompt =
    `Create a 30-second upbeat educational pop song about "${topic}". ` +
    `Style: bright, catchy pop with acoustic guitar and light percussion. Tempo: medium-fast. ` +
    `Include a short intro then a verse that teaches these key ideas in rhyming, memorable lyrics: ${excerpt}`;
  return {
    json: {
      ...item.json,
      lyria_prompt: lyriaPrompt,
    }
  };
});

// Extract audio from Lyria response, upload to Supabase Storage via fetch,
// then build the post row payload.
async function uploadToSupabase(supabaseUrl, serviceKey, filePath, audioBytes, mimeType) {
  const uploadUrl = `${supabaseUrl}/storage/v1/object/post-media/${filePath}`;
  const res = await fetch(uploadUrl, {
    method: 'POST',
    headers: {
      'apikey': serviceKey,
      'Authorization': `Bearer ${serviceKey}`,
      'Content-Type': mimeType,
      'x-upsert': 'true',
    },
    body: audioBytes,
  });
  if (!res.ok) {
    const body = await res.text();
    throw new Error(`Supabase upload failed: HTTP ${res.status} — ${body}`);
  }
  return { status: res.status };
}

const lyriaResponses = $input.all();
const buildData      = $('Build Lyria prompt').all();
const supabaseUrl    = $vars.SUPABASE_URL;
const serviceKey     = $vars.SUPABASE_SERVICE_KEY;

const results = [];
for (let i = 0; i < lyriaResponses.length; i++) {
  const response = lyriaResponses[i].json;
  const prev     = buildData[i].json;

  const parts     = response?.candidates?.[0]?.content?.parts ?? [];
  const audioPart = parts.find(p => p.inlineData?.mimeType?.startsWith('audio/'));
  if (!audioPart) continue;

  const b64 = audioPart.inlineData.data;
  if (!b64 || b64.length === 0) continue;

  const audioBytes = Buffer.from(b64, 'base64');
  const mimeType   = audioPart.inlineData.mimeType ?? 'audio/mpeg';
  const fileName   = `${prev.persona_slug}-${prev.chunk_index}-audio.mp3`;
  const filePath   = `${prev.material_id}/${fileName}`;

  await uploadToSupabase(supabaseUrl, serviceKey, filePath, audioBytes, mimeType);

  const mediaUrl = `${supabaseUrl}/storage/v1/object/public/post-media/${filePath}`;
  results.push({
    json: {
      material_id: prev.material_id,
      persona_id:  prev.persona_id,
      post_type:   prev.post_type,
      title:       prev.title ?? null,
      body:        prev.chunk_text.slice(0, 300),
      media_type:  'audio',
      media_url:   mediaUrl,
      source:      'n8n',
      sort_order:  prev.chunk_index * 4 + 2,
    }
  });
}
return results;
